const items = $input.all();

return items.map(item => {
  const data = item.json;
  const firstName   = (data.first_name || 'there').trim();
  const email       = (data.email     || '').trim();
  const sessionId   = data.session_id;
  const contactId   = data.contact_id;
  const scheduledAt = new Date(data.scheduled_at);

  const dateStr = scheduledAt.toLocaleDateString('en-US', {
    weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
    timeZone: 'America/New_York'
  });
  const timeStr = scheduledAt.toLocaleTimeString('en-US', {
    hour: '2-digit', minute: '2-digit', hour12: true,
    timeZone: 'America/New_York'
  });

  const html = [
    '<div style="font-family:sans-serif;max-width:600px;margin:0 auto">',
    '<h2 style="color:#2D6A6A;margin-bottom:16px">\u23F0 Your Session Starts in 2 Hours</h2>',
    '<p style="line-height:1.7;color:#333">Hi ' + firstName + ',</p>',
    '<p style="line-height:1.7;color:#333">Your coaching session with Arushi is just 2 hours away. Here are the details:</p>',
    '<div style="background:#f0f7f7;border-left:4px solid #2D6A6A;padding:16px;margin:20px 0;border-radius:0 4px 4px 0">',
    '<p style="margin:0;font-size:16px;color:#2D6A6A;font-weight:bold">' + dateStr + '</p>',
    '<p style="margin:6px 0 0;font-size:14px;color:#555">' + timeStr + ' EST</p>',
    '</div>',
    '<p style="line-height:1.7;color:#333"><strong>To join on time and make the most of your session:</strong></p>',
    '<ul style="color:#333;line-height:2.0;padding-left:20px">',
    '<li>Find a quiet, private space free from interruptions</li>',
    '<li>Have a glass of water and a pen and paper nearby</li>',
    '<li>Take a breath and arrive with one thing you most want clarity on today</li>',
    '<li>Join the call a minute or two early so we can start right on time</li>',
    '</ul>',
    '<p style="line-height:1.7;color:#333">See you very soon!</p>',
    '<p style="line-height:1.7;color:#333">Warmly,<br><strong>Arushi Bhardwaj</strong><br>SoulSynergy Coaching</p>',
    '<hr style="border:none;border-top:1px solid #eee;margin:24px 0">',
    '<p style="color:#999;font-size:12px">SoulSynergy Coaching &mdash; Uncover. Align. Achieve.</p>',
    '</div>'
  ].join('');

  const resendPayload = JSON.stringify({
    from: 'SoulSynergy Coaching <onboarding@resend.dev>',
    to: [email],
    subject: '\u23F0 Your coaching session is in 2 hours',
    html: html
  });

  return {
    json: {
      session_id:     sessionId,
      contact_id:     contactId,
      email:          email,
      resend_payload: resendPayload
    }
  };
});
